var input = $input.first().json;
var cfg = input.config || {};
var model = cfg.model || 'qwen2.5:14b';
var messages = [];
if (input.system_prompt) messages.push({role:'system',content:input.system_prompt});
var history = input.messages_history || [];
for (var i=0;i<history.length;i++) messages.push(history[i]);
messages.push({role:'user',content:input.message||''});
var INFERENCE_BASE = $env.INFERENCE_BASE_URL || 'http://genai-litellm.genai.svc.cluster.local:4000/v1';
var INFERENCE_KEY = $env.LITELLM_API_KEY || '';
var agentName = input.agent_name || 'chat';
var task = input.task || '';
var sessionId = input.session_id || '';
var metadata = {
  trace_name: agentName + (task ? '.' + task : '') + '.chat',
  session_id: sessionId || undefined,
  tags: ['agent:' + agentName, 'mode:chat', 'runtime:direct']
};
if (task) metadata.tags.push('task:' + task);
return [{json:{_url:INFERENCE_BASE+'/chat/completions', _auth:'Bearer '+INFERENCE_KEY, _body:{model:model,messages:messages,temperature:cfg.temperature||0.7,top_p:cfg.top_p||0.9,metadata:metadata}}}];

var resp = $input.first().json;
var output = '';
try { output = resp.choices[0].message.content || ''; } catch(e) { output = 'Error: '+(resp.message||JSON.stringify(resp)); }
return [{json:{output:output, intermediateSteps:[]}}];
